class CreditCardEncryptor:
    """
    Encrypts and decrypts credit card numbers using AES-256-GCM.

    Security features:
    - AES-256-GCM provides authenticated encryption (confidentiality + integrity)
    - Unique nonce/IV per encryption operation (prevents pattern analysis)
    - Key managed through SecureKeyManager (not hardcoded)
    - Input validation to reject malformed card numbers
    - Minimal logging (never logs card numbers or keys)

    PCI DSS Compliance Notes:
    - Consider whether you truly need to store card numbers at all.
      Use tokenization via your payment processor (Stripe, Braintree, etc.) instead.
    - If you must store them, ensure your infrastructure meets PCI DSS requirements.
    - Implement access controls, audit logging, and key rotation.
    """

    # AES-256-GCM nonce size in bytes
    NONCE_SIZE = 12
    # AES-256 key size in bytes
    KEY_SIZE = 32

    def __init__(self, key_manager=None):
        self.key_manager = key_manager or SecureKeyManager()
        self._cipher = None

    @staticmethod
    def generate_key():
        """Generate a new AES-256 encryption key. Store this in your secrets manager."""
        key = AESGCM.generate_key(bit_length=256)
        return base64.urlsafe_b64encode(key).decode("utf-8")

    def _get_cipher(self):
        if self._cipher is None:
            raw_key = self.key_manager.get_key()
            # Decode if base64 encoded
            try:
                key_bytes = base64.urlsafe_b64decode(raw_key)
            except Exception:
                key_bytes = raw_key

            if len(key_bytes) != self.KEY_SIZE:
                raise ValueError(
                    f"Encryption key must be {self.KEY_SIZE} bytes (AES-256). "
                    f"Got {len(key_bytes)} bytes. Use CreditCardEncryptor.generate_key() to create one."
                )
            self._cipher = AESGCM(key_bytes)
        return self._cipher

    @staticmethod
    def validate_card_number(card_number):
        """
        Validate credit card number format using Luhn algorithm.
        Strips spaces and dashes before validation.
        """
        # Remove spaces and dashes
        cleaned = re.sub(r"[\s\-]", "", card_number)

        # Check it's all digits and reasonable length
        if not cleaned.isdigit():
            raise ValueError("Card number must contain only digits, spaces, or dashes.")
        if not (13 <= len(cleaned) <= 19):
            raise ValueError("Card number must be between 13 and 19 digits.")

        # Luhn algorithm check
        digits = [int(d) for d in cleaned]
        checksum = 0
        reverse_digits = digits[::-1]
        for i, d in enumerate(reverse_digits):
            if i % 2 == 1:
                d *= 2
                if d > 9:
                    d -= 9
            checksum += d

        if checksum % 10 != 0:
            raise ValueError("Card number failed Luhn check - invalid card number.")

        return cleaned

    def encrypt(self, card_number, associated_data=None):
        """
        Encrypt a credit card number.

        Args:
            card_number: The credit card number string.
            associated_data: Optional additional authenticated data (e.g., customer ID).
                           This data is authenticated but NOT encrypted.
                           Useful to bind the ciphertext to a specific context.

        Returns:
            A base64-encoded string containing the nonce + ciphertext + auth tag.
        """
        # Validate input
        cleaned_card = self.validate_card_number(card_number)

        # Generate a unique nonce for each encryption
        nonce = os.urandom(self.NONCE_SIZE)

        # Prepare associated data
        aad = None
        if associated_data:
            aad = associated_data.encode("utf-8") if isinstance(associated_data, str) else associated_data

        # Encrypt
        cipher = self._get_cipher()
        ciphertext = cipher.encrypt(nonce, cleaned_card.encode("utf-8"), aad)

        # Combine nonce + ciphertext for storage
        encrypted_blob = nonce + ciphertext

        # Return as base64 string for safe database storage
        return base64.urlsafe_b64encode(encrypted_blob).decode("utf-8")

    def decrypt(self, encrypted_data, associated_data=None):
        """
        Decrypt a credit card number.

        Args:
            encrypted_data: The base64-encoded encrypted string from encrypt().
            associated_data: Must match the associated_data used during encryption.

        Returns:
            The decrypted credit card number string.
        """
        if not encrypted_data:
            raise ValueError("No encrypted data provided.")

        # Decode from base64
        encrypted_blob = base64.urlsafe_b64decode(encrypted_data)

        # Extract nonce and ciphertext
        if len(encrypted_blob) < self.NONCE_SIZE + 16:  # minimum: nonce + 16-byte auth tag
            raise ValueError("Encrypted data is too short - possibly corrupted.")

        nonce = encrypted_blob[:self.NONCE_SIZE]
        ciphertext = encrypted_blob[self.NONCE_SIZE:]

        # Prepare associated data
        aad = None
        if associated_data:
            aad = associated_data.encode("utf-8") if isinstance(associated_data, str) else associated_data

        # Decrypt
        cipher = self._get_cipher()
        try:
            plaintext = cipher.decrypt(nonce, ciphertext, aad)
        except Exception as e:
            raise ValueError(
                "Decryption failed. Possible causes: wrong key, corrupted data, "
                "or mismatched associated_data."
            ) from e

        return plaintext.decode("utf-8")

    def get_masked_card(self, card_number):
        """Return a masked version for display (e.g., **** **** **** 1234)."""
        cleaned = re.sub(r"[\s\-]", "", card_number)
        if len(cleaned) < 4:
            return "****"
        last_four = cleaned[-4:]
        return f"**** **** **** {last_four}"

    def get_last_four(self, encrypted_data, associated_data=None):
        """Decrypt and return only the last 4 digits (for display purposes)."""
        full_number = self.decrypt(encrypted_data, associated_data)
        return full_number[-4:]


