class BatchCreditCardEncryptor:
    """
    Optimized for processing thousands of transactions.
    Reuses the cipher object and minimizes overhead.
    """

    def __init__(self, encryptor=None):
        self.encryptor = encryptor or CreditCardEncryptor()
        # Pre-initialize the cipher to avoid lazy-loading overhead during batch
        self.encryptor._get_cipher()

    def encrypt_batch(self, card_entries):
        """
        Encrypt a batch of card numbers.

        Args:
            card_entries: List of dicts with 'customer_id' and 'card_number' keys.

        Returns:
            List of dicts with encryption results and any errors.
        """
        results = []
        for entry in card_entries:
            try:
                encrypted = self.encryptor.encrypt(
                    entry["card_number"],
                    associated_data=entry.get("customer_id")
                )
                results.append({
                    "customer_id": entry.get("customer_id"),
                    "encrypted_card": encrypted,
                    "masked_card": self.encryptor.get_masked_card(entry["card_number"]),
                    "success": True,
                })
            except Exception as e:
                results.append({
                    "customer_id": entry.get("customer_id"),
                    "success": False,
                    "error": str(e),
                })
        return results

    def decrypt_batch(self, encrypted_entries):
        """
        Decrypt a batch of encrypted card numbers.

        Args:
            encrypted_entries: List of dicts with 'encrypted_card' and optional 'customer_id'.

        Returns:
            List of dicts with decryption results.
        """
        results = []
        for entry in encrypted_entries:
            try:
                decrypted = self.encryptor.decrypt(
                    entry["encrypted_card"],
                    associated_data=entry.get("customer_id")
                )
                results.append({
                    "customer_id": entry.get("customer_id"),
                    "card_number": decrypted,
                    "success": True,
                })
            except Exception as e:
                results.append({
                    "customer_id": entry.get("customer_id"),
                    "success": False,
                    "error": str(e),
                })
        return results


